import React, { useEffect, useState } from 'react';
import { Pie, Bar, Line, Doughnut, Scatter } from 'react-chartjs-2';
import axios from 'axios';
import './Reports.css';

import {
  Chart as ChartJS,
  ArcElement,
  BarElement,
  LineElement,
  PointElement,
  CategoryScale,
  LinearScale,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(
  ArcElement,
  BarElement,
  LineElement,
  PointElement,
  CategoryScale,
  LinearScale,
  Title,
  Tooltip,
  Legend
);

function Reports() {
  const [data, setData] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchAllData = async () => {
      try {
        const endpoints = [
          'http://localhost:5000/api/ml/analytics',
          'http://localhost:5000/api/ml/ml-demand-prediction',
          'http://localhost:5000/api/ml/category-analysis',
          'http://localhost:5000/api/ml/brand-analysis',
          'http://localhost:5000/api/ml/top-products',
          'http://localhost:5000/api/ml/price-distribution',
          'http://localhost:5000/api/ml/rating-distribution',
          'http://localhost:5000/api/ml/next-month-forecast',
          'http://localhost:5000/api/category-product-count',
          'http://localhost:5000/api/brand-product-distribution',
          'http://localhost:5000/api/price-analysis',
          'http://localhost:5000/api/stock-analysis',
          'http://localhost:5000/api/product-popularity',
          'http://localhost:5000/api/purchase-analysis',
          'http://localhost:5000/api/conversion-rate',
          'http://localhost:5000/api/rating-analysis',
          'http://localhost:5000/api/price-vs-purchase',
          'http://localhost:5000/api/brand-performance',
          'http://localhost:5000/api/category-sales-performance',
          'http://localhost:5000/api/kmeans-clustering',
          'http://localhost:5000/api/decision-tree-prediction'
        ];

        const responses = await Promise.allSettled(endpoints.map(ep => axios.get(ep)));
        const newData = {};

        responses.forEach((response, idx) => {
          if (response.status === 'fulfilled') {
            newData[`data${idx}`] = response.value.data;
          }
        });

        setData(newData);
        setError(null);
      } catch (error) {
        console.error('Error fetching data:', error);
        setError(error.message);
      } finally {
        setLoading(false);
      }
    };
    fetchAllData();
  }, []);

  if (loading) {
    return <div className="reports-container"><p>⏳ Loading analytics...</p></div>;
  }

  const cardStyle = {
    background: 'linear-gradient(135deg, #1a3a52 0%, #2d5a80 100%)',
    color: 'white',
    padding: '24px',
    borderRadius: '12px',
    textAlign: 'center',
    boxShadow: '0 8px 16px rgba(26, 58, 82, 0.2)',
    marginBottom: '15px'
  };

  const valueStyle = {
    fontSize: '2rem',
    fontWeight: 'bold',
    margin: '0',
    color: '#ffd700'
  };

  return (
    <div className="reports-container">
      <h1>📊 Complete Analytics Dashboard (20 Analyses)</h1>

      {/* PREVIOUS 8 ANALYSES */}

      {/* Forecast */}
      {data.data7 && (
        <div className="chart-section">
          <h2>🤖 Next Month Forecast (Linear Regression)</h2>
          <div className="prediction-cards">
            <div style={cardStyle}>
              <h3>Current Month Sales</h3>
              <p style={valueStyle}>₹{Math.round(data.data7.currentMonthSales * 83)}</p>
            </div>
            <div style={cardStyle}>
              <h3>Forecasted Next Month</h3>
              <p style={valueStyle}>₹{Math.round(data.data7.nextMonthForecast * 83)}</p>
            </div>
            <div style={cardStyle}>
              <h3>Growth Rate</h3>
              <p style={{...valueStyle, color: '#4CAF50'}}>📈 {data.data7.growthRate}</p>
            </div>
            <div style={cardStyle}>
              <h3>Model Confidence</h3>
              <p style={valueStyle}>{(parseFloat(data.data7.confidence) * 100).toFixed(0)}%</p>
            </div>
          </div>
        </div>
      )}

      {/* Category Distribution */}
      {data.data0?.pie?.labels && (
        <div className="chart-section">
          <h2>📊 Category Distribution</h2>
          <div style={{ position: 'relative', height: '400px' }}>
            <Pie data={data.data0.pie} options={{ maintainAspectRatio: false }} />
          </div>
        </div>
      )}

      {/* Average Price by Category */}
      {data.data0?.bar?.labels && (
        <div className="chart-section">
          <h2>💰 Average Price by Category</h2>
          <div style={{ position: 'relative', height: '400px' }}>
            <Bar data={data.data0.bar} options={{ maintainAspectRatio: false }} />
          </div>
        </div>
      )}

      {/* Monthly Sales Trend */}
      {data.data0?.line?.labels && (
        <div className="chart-section">
          <h2>📈 Monthly Sales Trend</h2>
          <div style={{ position: 'relative', height: '400px' }}>
            <Line data={data.data0.line} options={{ maintainAspectRatio: false }} />
          </div>
        </div>
      )}

      {/* Price Distribution */}
      {data.data5?.ranges && (
        <div className="chart-section">
          <h2>💵 Price Range Distribution</h2>
          <div style={{ position: 'relative', height: '400px' }}>
            <Bar data={{
              labels: data.data5.ranges,
              datasets: [{
                label: 'Number of Products',
                data: data.data5.counts,
                backgroundColor: 'rgba(153, 102, 255, 0.2)',
                borderColor: 'rgba(153, 102, 255, 1)',
                borderWidth: 1
              }]
            }} options={{ maintainAspectRatio: false }} />
          </div>
        </div>
      )}

      {/* Rating Distribution */}
      {data.data6?.ratings && (
        <div className="chart-section">
          <h2>⭐ Rating Distribution</h2>
          <div style={{ position: 'relative', height: '400px' }}>
            <Doughnut data={{
              labels: data.data6.ratings.map(r => `${r} Stars`),
              datasets: [{
                data: data.data6.counts,
                backgroundColor: ['#FF6384', '#36A2EB', '#FFCE56', '#4BC0C0', '#9966FF']
              }]
            }} options={{ maintainAspectRatio: false }} />
          </div>
        </div>
      )}

      {/* Top Products */}
      {data.data4?.topProducts && (
        <div className="chart-section">
          <h2>🏆 Top 15 Best Selling Products</h2>
          <table className="products-table">
            <thead>
              <tr>
                <th>Product Name</th>
                <th>Category</th>
                <th>Price</th>
                <th>Sales</th>
                <th>Rating</th>
              </tr>
            </thead>
            <tbody>
              {data.data4.topProducts.map((product, idx) => (
                <tr key={idx}>
                  <td>{product.name}</td>
                  <td>{product.category}</td>
                  <td>₹{Math.round(product.price)}</td>
                  <td>{product.sales}</td>
                  <td>⭐ {product.rating.toFixed(1)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Category Analysis */}
      {data.data2?.categories && (
        <div className="chart-section">
          <h2>📋 Category Analysis</h2>
          <table className="analysis-table">
            <thead>
              <tr>
                <th>Category</th>
                <th>Avg Price</th>
                <th>Min Price</th>
                <th>Max Price</th>
                <th>Total Sales</th>
                <th>Avg Rating</th>
              </tr>
            </thead>
            <tbody>
              {data.data2.categories.map((cat, idx) => (
                <tr key={idx}>
                  <td>{cat.category}</td>
                  <td>₹{Math.round(cat.avgPrice)}</td>
                  <td>₹{Math.round(cat.minPrice)}</td>
                  <td>₹{Math.round(cat.maxPrice)}</td>
                  <td>{cat.totalSales}</td>
                  <td>⭐ {cat.avgRating.toFixed(1)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Brand Analysis */}
      {data.data3?.brands && (
        <div className="chart-section">
          <h2>🏢 Top Brands Performance</h2>
          <table className="analysis-table">
            <thead>
              <tr>
                <th>Brand</th>
                <th>Total Sales</th>
                <th>Avg Rating</th>
                <th>Avg Price</th>
              </tr>
            </thead>
            <tbody>
              {data.data3.brands.map((brand, idx) => (
                <tr key={idx}>
                  <td>{brand.brand}</td>
                  <td>{brand.totalSales}</td>
                  <td>⭐ {brand.avgRating.toFixed(1)}</td>
                  <td>₹{Math.round(brand.avgPrice)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* ML Predictions */}
      {data.data1?.results && (
        <div className="chart-section">
          <h2>🎯 ML Demand Predictions (Top 10)</h2>
          <div className="metrics">
            <div className="metric">
              <span>Model Accuracy (R²):</span>
              <strong>{(data.data1.accuracy * 100).toFixed(1)}%</strong>
            </div>
            <div className="metric">
              <span>RMSE:</span>
              <strong>{data.data1.rmse}</strong>
            </div>
          </div>
          <table className="predictions-table">
            <thead>
              <tr>
                <th>Product</th>
                <th>Category</th>
                <th>Price</th>
                <th>Actual Sales</th>
                <th>Predicted Sales</th>
              </tr>
            </thead>
            <tbody>
              {data.data1.results.slice(0, 10).map((item, idx) => (
                <tr key={idx}>
                  <td>{item.name}</td>
                  <td>{item.category}</td>
                  <td>₹{Math.round(item.price)}</td>
                  <td>{Math.round(item.actual)}</td>
                  <td className="positive">{Math.round(item.predicted)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* NEW 12 ANALYSES */}

      {/* 1. Category Product Count */}
